@namespace Lumeo

@if (Variant == SpinnerVariant.Ring)
{
    <div class="@WrapperClass" @attributes="AdditionalAttributes">
        <svg class="@RingCssClass" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
            <circle class="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" stroke-width="4"></circle>
            <path class="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
        </svg>
        @if (!string.IsNullOrEmpty(Label))
        {
            <span class="text-sm text-muted-foreground">@Label</span>
        }
    </div>
}
else if (Variant == SpinnerVariant.Dots)
{
    <div class="@WrapperClass" @attributes="AdditionalAttributes">
        <div class="@DotsContainerClass">
            <div class="@DotClass" style="animation-delay: 0ms"></div>
            <div class="@DotClass" style="animation-delay: 150ms"></div>
            <div class="@DotClass" style="animation-delay: 300ms"></div>
        </div>
        @if (!string.IsNullOrEmpty(Label))
        {
            <span class="text-sm text-muted-foreground">@Label</span>
        }
    </div>
}
else if (Variant == SpinnerVariant.Bars)
{
    <div class="@WrapperClass" @attributes="AdditionalAttributes">
        <div class="@BarsContainerClass">
            <div class="@BarClass" style="height: 60%; animation-delay: 0ms"></div>
            <div class="@BarClass" style="height: 100%; animation-delay: 150ms"></div>
            <div class="@BarClass" style="height: 60%; animation-delay: 300ms"></div>
        </div>
        @if (!string.IsNullOrEmpty(Label))
        {
            <span class="text-sm text-muted-foreground">@Label</span>
        }
    </div>
}

@code {
    [Parameter] public Lumeo.Size Size { get; set; } = Lumeo.Size.Md;
    [Parameter] public SpinnerVariant Variant { get; set; } = SpinnerVariant.Ring;
    [Parameter] public string? Label { get; set; }
    [Parameter] public string? Color { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string WrapperClass => Cx.Join("inline-flex items-center gap-2", Color, Class);

    private string RingCssClass => Cx.Join("animate-spin", SizeClasses);

    private string SizeClasses => Size switch
    {
        Lumeo.Size.Sm => "h-4 w-4",
        Lumeo.Size.Md => "h-6 w-6",
        Lumeo.Size.Lg => "h-8 w-8",
        _ => "h-6 w-6"
    };

    private string DotsContainerClass => $"flex items-center {DotGapClass}".Trim();

    private string DotGapClass => Size switch
    {
        Lumeo.Size.Sm => "gap-0.5",
        Lumeo.Size.Md => "gap-1",
        Lumeo.Size.Lg => "gap-1.5",
        _ => "gap-1"
    };

    private string DotClass
    {
        get
        {
            var sizeClass = Size switch
            {
                Lumeo.Size.Sm => "h-1.5 w-1.5",
                Lumeo.Size.Md => "h-2 w-2",
                Lumeo.Size.Lg => "h-3 w-3",
                _ => "h-2 w-2"
            };
            return $"{sizeClass} rounded-full bg-current animate-bounce";
        }
    }

    private string BarsContainerClass
    {
        get
        {
            var heightClass = Size switch
            {
                Lumeo.Size.Sm => "h-3",
                Lumeo.Size.Md => "h-4",
                Lumeo.Size.Lg => "h-6",
                _ => "h-4"
            };
            return $"flex items-end gap-0.5 {heightClass}";
        }
    }

    private string BarClass
    {
        get
        {
            var widthClass = Size switch
            {
                Lumeo.Size.Sm => "w-0.5",
                Lumeo.Size.Md => "w-1",
                Lumeo.Size.Lg => "w-1.5",
                _ => "w-1"
            };
            return $"{widthClass} bg-current rounded-sm animate-pulse";
        }
    }

    public enum SpinnerVariant { Ring, Dots, Bars }
}
